public class Shop : MonoBehaviour
{
    public int itemPrice = 100;

    public void BuyItem(Player player)
    {
        if (player.currency >= itemPrice)
        {
            player.SpendCurrency(itemPrice);
            Debug.Log("Item purchased successfully.");
        }
        else
